from typing import List


def string_xor(a: str, b: str) -> str:
    """ Input are two strings a and b consisting only of 1s and 0s.
    Perform binary XOR on these inputs and return result also as a string.
    >>> string_xor('010', '110')
    '100'
    """
    result = []
    for char_a, char_b in zip(a, b):
        if char_a == char_b:
            result.append('0')
        else:
            result.append('1')
    return "".join(result)

def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    result = []
    for char in string:
        if char.islower():
            result.append(char.upper())
        elif char.isupper():
            result.append(char.lower())
        else:
            result.append(char)
    return "".join(result)

def encode_shift(s: str):
    """
    returns encoded string by shifting every character by 5 in the alphabet.
    """
    return "".join([chr(((ord(ch) + 5 - ord("a")) % 26) + ord("a")) for ch in s])


def decode_shift(s: str):
    """
    takes as input string encoded with encode_shift function. Returns decoded string.
    """
    return "".join([chr(((ord(ch) - 5 - ord("a")) % 26) + ord("a")) for ch in s])

def fruit_distribution(s, n):
    """
    Extracts the number of apples and oranges from the string s and subtracts
    them from the total count n to find the number of mangoes.
    """
    # Split the string into words and filter for numeric sequences
    numbers = []
    for word in s.split():
        if word.isdigit():
            numbers.append(int(word))

    # Subtract the extracted numbers from the total count
    return n - sum(numbers)

def pluck(arr):
    """
    Plucks the node with the smallest even value from the array.
    If multiple nodes have the same smallest even value, the one with the smallest index is chosen.
    Returns [value, index] or [] if no even value exists.
    """
    if not arr:
        return []

    min_even_val = float('inf')
    min_even_idx = -1

    for i, val in enumerate(arr):
        if val % 2 == 0:
            if val < min_even_val:
