def anti_shuffle(s):
    """
    Write a function that takes a string and returns an ordered version of it.
    Ordered version of string, is a string where all words (separated by space)
    are replaced by a new word where all the characters arranged in
    ascending order based on ascii value.
    Note: You should keep the order of words and blank spaces in the sentence.
    """
    if not s:
        return s

    result = []
    current_word = []

    for char in s:
        if char == ' ':
            if current_word:
                result.append("".join(sorted(current_word)))
                current_word = []
            result.append(char)
        else:
            current_word.append(char)

    if current_word:
        result.append("".join(sorted(current_word)))

    return "".join(result)

def get_row(lst, x):
    """
    Finds all occurrences of integer x in a 2D nested list and returns
    their coordinates (row, col) sorted by row ascending and column descending.
    """
    coords = []
    for row_idx, row in enumerate(lst):
        for col_idx, value in enumerate(row):
            if value == x:
                coords.append((row_idx, col_idx))

    # Sort by row ascending (x[0]), then by column descending (-x[1])
    coords.sort(key=lambda coord: (coord[0], -coord[1]))

    return coords

def next_smallest(lst):
    """
    Returns the 2nd smallest unique element of the list.
    Returns None if there is no such element.
    """
    if len(lst) < 2:
        return None

    first_min = float('inf')
    second_min = float('inf')

    for num in lst:
        if num < first_min:
            second_min = first_min
            first_min = num
        elif first_min < num < second_min:
            second_min = num

    if second_min == float('inf'):
        return None

    return second_min

def encode(message):
    """
    Write a function that takes a message, and encodes in such a 
    way that it swaps case of all letters, replaces all vowels in 
    the message with the letter that appears 2 places ahead of that 
    vowel in the english alphabet. 
    Assume only letters. 

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """
    vowels = "aeiouAEIOU"
    vowel_map = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    }

    result = []
    for char in message:
        if char in vowel_map:
            # Replace vowel with shifted letter
            transformed = vowel_map[char]
            # Swap case of the shifted letter
            if transformed.isupper():
                result.append(transformed.lower())
            else:
                result.append(transformed.upper())
        else:
            # Swap case of non-vowel characters
            if char.isupper():
                result.append(char.lower())
            elif char.islower():
                result.append(char.upper())
            else:
                result.append(char)

    return "".join(result)

