def count_up_to(n):
    """Implement a function that takes an non-negative integer and returns an array of the first n
    integers that are prime numbers and less than n.
    """
    if n < 2:
        return []

    primes = []
    for num in range(2, n):
        if len(primes) >= n:
            break

        is_prime = True
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                is_prime = False
                break

        if is_prime:
            primes.append(num)

    return primes

def unique_digits(x):
    """Given a list of positive integers x. return a sorted list of all 
    elements that hasn't any even digit.

    Note: Returned list should be sorted in increasing order.

    For example:
    >>> unique_digits([15, 33, 1422, 1])
    [1, 15, 33]
    >>> unique_digits([152, 323, 1422, 10])
    []
    """
    result = []
    even_digits = {'0', '2', '4', '6', '8'}

    for num in x:
        num_str = str(num)
        has_even = False
        for digit in num_str:
            if digit in even_digits:
                has_even = True
                break
        if not has_even:
            result.append(num)

    return sorted(result)

def even_odd_palindrome(n):
    """
    Given a positive integer n, return a tuple that has the number of even and odd
    integer palindromes that fall within the range(1, n), inclusive.
    """
    even_count = 0
    odd_count = 0

    for i in range(1, n + 1):
        s = str(i)
        if s == s[::-1]:
            if i % 2 == 0:
                even_count += 1
            else:
                odd_count += 1

    return (even_count, odd_count)

def calculate_signed_digit_sum(num):
    """
    Calculates the sum of digits based on the signed-digit rule:
    - If negative, the first digit is negative, others are positive.
    - If positive, all digits are positive.
    """
    s = str(num)
    if not s:
        return 0

    if s[0] == '-':
        # Handle negative number logic: -123 -> -1, 2, 3
        if len(s) == 1:
            return 0
        first_digit = -int(s[1])
        remaining_digits_sum = sum(int(d) for d in s[2:])
        return first_digit + remaining_digits_sum
    else:
        # Handle positive number logic
        return sum(int(d) for d in s)

def count_nums(arr):
    """
    Write a function count_nums which takes an array of integers and returns
    the number of elements which has a sum of digits > 0.
    """
    count = 0
    for num in arr:
        if calculate_signed_digit_sum(num) > 0:
            count += 1
    return count

def histogram(test):
    """Given a string representing a space separated lowercase letters, return a dictionary
    of the letter with the most repetition and containing the corresponding count.
    If several letters have the same occurrence, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}

    """
    if not test.strip():
        return {}

    letters = test.split()
    counts = {}
    for char in letters:
        counts[char] = counts.get(char, 0) + 1

    if not counts:
        return {}

    max_freq = max(counts.values())

    return {char: count for char, count in counts.items() if count == max_freq}

