def get_closest_vowel(word):
    if len(word) < 3:
        return ""

    vowels = set("aeiouAEIOU")

    # Iterate from the second to last character down to the second character
    # (index 1 to len(word) - 2) to satisfy boundary constraints.
    # We iterate backwards to find the "closest" from the right.
    for i in range(len(word) - 2, 0, -1):
        char = word[i]
        if char in vowels:
            left_char = word[i - 1]
            right_char = word[i + 1]

            # Check if both neighbors are consonants
            if left_char not in vowels and right_char not in vowels:
                return char

    return ""

