def get_odd_collatz(n):
    """
    Given a positive integer n, return a sorted list that has the odd numbers in collatz sequence.
    """
    if n < 1:
        return []

    odd_numbers = set()
    current = n

    while True:
        if current % 2 != 0:
            odd_numbers.add(current)

        if current == 1:
            break

        if current % 2 == 0:
            current = current // 2
        else:
            current = 3 * current + 1

    return sorted(list(odd_numbers))

def valid_date(date):
    """
    Validates a date string based on specific rules:
    1. Not empty.
    2. Format mm-dd-yyyy (10 characters).
    3. Month between 1 and 12.
    4. Days: 1-31 for (1,3,5,7,8,10,12), 1-30 for (4,6,9,11), 1-29 for (2).
    """
    if not date or len(date) != 10:
        return False

    parts = date.split('-')
    if len(parts) != 3:
        return False

    m_str, d_str, y_str = parts

    if not (m_str.isdigit() and d_str.isdigit() and y_str.isdigit()):
        return False

    month = int(m_str)
    day = int(d_str)
    year = int(y_str)

    if month < 1 or month > 12:
        return False

    if month in [1, 3, 5, 7, 8, 10, 12]:
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        if day < 1 or day > 30:
            return False
    elif month == 2:
        if day < 1 or day > 29:
            return False
    else:
        return False

    return True

