def is_sorted(lst):
    '''
    Given a list of numbers, return whether or not they are sorted
    in ascending order. If list has more than 1 duplicate of the same
    number, return False. Assume no negative numbers and only integers.
    '''
    if not lst:
        return True

    counts = {}
    for i in range(len(lst)):
        # Check duplicate constraint
        val = lst[i]
        counts[val] = counts.get(val, 0) + 1
        if counts[val] > 2:
            return False

        # Check order verification
        if i > 0:
            if lst[i] < lst[i-1]:
                return False

    return True

def intersection(interval1, interval2):
    """
    Determines whether the length of the intersection of two closed intervals is a prime number.
    """
    # Calculate the bounds of the intersection
    start_max = max(interval1[0], interval2[0])
    end_min = min(interval1[1], interval2[1])

    # Calculate the length of the intersection
    # If start_max > end_min, there is no intersection
    if start_max >= end_min:
        length = 0
    else:
        length = end_min - start_max

    # Primality check
    if length < 2:
        return "NO"

    for i in range(2, int(length**0.5) + 1):
        if length % i == 0:
            return "NO"

    return "YES"

def minPath(grid, k):
    """
    Finds the lexicographically smallest path of length k in an N x N grid.
    The strategy involves finding the smallest value in the grid (which is 1)
    and its smallest neighbor. The path will oscillate between these two
    to maintain the lexicographical minimum.
    """
    n = len(grid)

    def get_neighbors(r, c, n):
        neighbors = []
        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < n and 0 <= nc < n:
                neighbors.append((nr, nc))
        return neighbors

    def find_cell_by_value(grid, value):
        for r in range(n):
            for c in range(n):
                if grid[r][c] == value:
                    return r, c
        return None

    # The smallest value in the grid is always 1.
    # We find its location and its smallest neighbor.
    r1, c1 = find_cell_by_value(grid, 1)

    neighbors = get_neighbors(r1, c1, n)
    min_neighbor_val = float('inf')

    for nr, nc in neighbors:
        if grid[nr][nc] < min_neighbor_val:
            min_neighbor_val = grid[nr][nc]

    # If k=1, the smallest path is just [1]
    if k == 1:
        return [1]

    # If k > 1, the lexicographically smallest path starts with 1,
    # then goes to its smallest neighbor, then back to 1, and so on.
    # This is because 1 is the absolute minimum possible value at any step,
    # and min_neighbor_val is the smallest possible value that can follow 1.
    res = []
    for i in range(k):
        if i % 2 == 0:
            res.append(1)
        else:
            res.append(min_neighbor_val)

    return res

def is_nested(string):
    """
    Analyzes a string of square brackets to determine if a nested structure exists.
    A nested structure is defined as a valid pair of brackets that encloses 
    at least one other bracket.
    """
    count = 0
    max_depth = 0
    for char in string:
        if char == '[':
            count += 1
        elif char == ']':
            count -= 1

        if count < 0:
            count = 0

        if count > max_depth:
            max_depth = count

    # A max_depth of 2 or more indicates that at least one bracket 
    # was opened while another was already open, creating a nesting.
    return max_depth >= 2

